import{_ as o,o as a,c as t,a2 as i}from"./chunks/framework.B8zgMDLd.js";const b=JSON.parse('{"title":"Organize The Inbox","description":"","frontmatter":{},"headers":[],"relativePath":"guides/organize-inbox.md","filePath":"guides/organize-inbox.md"}'),n={name:"guides/organize-inbox.md"};function r(l,e,s,d,c,h){return a(),t("div",null,[...e[0]||(e[0]=[i('<h1 id="organize-the-inbox" tabindex="-1">Organize The Inbox <a class="header-anchor" href="#organize-the-inbox" aria-label="Permalink to &quot;Organize The Inbox&quot;">​</a></h1><p>Inbox review turns quick captures into usable knowledge.</p><h2 id="remove-a-note-from-inbox" tabindex="-1">Remove A Note From Inbox <a class="header-anchor" href="#remove-a-note-from-inbox" aria-label="Permalink to &quot;Remove A Note From Inbox&quot;">​</a></h2><p>When a note is organized enough, mark it as organized. Use <code>Cmd+E</code> on macOS or <code>Ctrl+E</code> on Windows and Linux, or click the organize action in the breadcrumb bar.</p><p>That action is what removes the note from Inbox. If auto-advance is enabled in Settings &gt; Workflow, Tolaria opens the next Inbox item immediately after you mark the current note organized.</p><h2 id="review-checklist" tabindex="-1">Review Checklist <a class="header-anchor" href="#review-checklist" aria-label="Permalink to &quot;Review Checklist&quot;">​</a></h2><ul><li>Rename unclear notes.</li><li>Add or correct the first H1.</li><li>Set <code>type</code>.</li><li>Add <code>status</code> for actionable notes.</li><li>Add <code>belongs_to</code>, <code>related_to</code>, or other relationship fields when useful.</li><li>Archive or delete notes that no longer matter.</li></ul><h2 id="make-notes-navigable" tabindex="-1">Make Notes Navigable <a class="header-anchor" href="#make-notes-navigable" aria-label="Permalink to &quot;Make Notes Navigable&quot;">​</a></h2><p>A note is organized when you can answer:</p><ul><li>What kind of thing is this?</li><li>What is it connected to?</li><li>What is this useful for?</li><li>What will I do with it?</li></ul><h2 id="avoid-over-structuring" tabindex="-1">Avoid Over-Structuring <a class="header-anchor" href="#avoid-over-structuring" aria-label="Permalink to &quot;Avoid Over-Structuring&quot;">​</a></h2><p>Do not add fields just because they exist. Add the structure that will help future navigation, review, or automation.</p>',12)])])}const m=o(n,[["render",r]]);export{b as __pageData,m as default};
